"use strict";parserFactory.register("secondlifetranslations.com",()=>new SecondlifetranslationsParser);class SecondlifetranslationsParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("button.accordion").nextElementSibling;return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1.entry-title")}findCoverImageUrl(e){let t=e.querySelector("img.novelcover");return null===t?null:t.src}preprocessRawDom(e){let t=this.findContent(e);util.removeChildElementsMatchingSelector(t,".code-block");let r=[...t.querySelectorAll("span.modern-footnotes-footnote__note")];this.moveFootnotes(e,t,r)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-entry-content")]}}